     4→
     5→describe('AppController', () => {
     6→    let appController: AppController;
     7→    let appService: AppService;
     8→
     9→    beforeEach(async () => {
    10→        const app: TestingModule = await Test.createTestingModule({
    11→            controllers: [AppController],
    12→            providers: [AppService]
    13→        }).compile();
    14→
    15→        appController = app.get<AppController>(AppController);
    16→        appService = app.get<AppService>(AppService);
    17→    });
    18→
    19→    describe('Controller Initialization', () => {
    20→        it('should be defined', () => {
    21→            expect(appController).toBeDefined();
    22→        });
    23→
    24→        it('should have AppService injected', () => {
    25→            expect(appService).toBeDefined();
    26→            expect(appService).toBeInstanceOf(AppService);
    27→        });
    28→    });
    29→
    30→    describe('GET /up - Health Check Endpoint', () => {
    31→        it('should return true indicating server is running', () => {
    32→            const result = appController.running();
    33→            expect(result).toBe(true);
    34→        });
    35→
    36→        it('should return boolean type', () => {
    37→            const result = appController.running();
    38→            expect(typeof result).toBe('boolean');
    39→        });
    40→
    41→        it('should consistently return true on multiple calls', () => {
    42→            const result1 = appController.running();
    43→            const result2 = appController.running();
    44→            const result3 = appController.running();
    45→
    46→            expect(result1).toBe(true);
    47→            expect(result2).toBe(true);
    48→            expect(result3).toBe(true);
    49→        });
    50→    });
    51→
    52→    describe('Controller Dependencies', () => {
    53→        it('should have access to AppService', () => {
    54→            expect((appController as any).appService).toBeDefined();
    55→            expect((appController as any).appService).toBeInstanceOf(AppService);
    56→        });
    57→    });
    58→
    59→    describe('HTTP Method Mapping', () => {
    60→        it('should have running method mapped to GET request', () => {
    61→            // Verify the method exists and is callable
    62→            expect(typeof appController.running).toBe('function');
    63→            expect(appController.running()).toBe(true);
    64→        });
    65→    });
    66→
    67→    describe('Error Handling', () => {
    68→        it('should handle method calls without throwing errors', () => {
    69→            expect(() => appController.running()).not.toThrow();
    70→        });
    71→    });
    72→
    73→    describe('Performance', () => {
    74→        it('should respond quickly to health check requests', () => {
    75→            const startTime = Date.now();
    76→            appController.running();
    77→            const endTime = Date.now();
    78→
    79→            // Health check should be very fast (under 10ms)
    80→            expect(endTime - startTime).toBeLessThan(10);
    81→        });
    82→
    83→        it('should handle multiple concurrent calls efficiently', () => {
    84→            const startTime = Date.now();
    85→
    86→            // Simulate multiple concurrent calls
    87→            const promises = Array.from({ length: 100 }, () =>
    88→                Promise.resolve(appController.running())
    89→            );
    90→
    91→            Promise.all(promises).then(results => {
    92→                const endTime = Date.now();
    93→
    94→                // All should return true
    95→                results.forEach(result => expect(result).toBe(true));
    96→
    97→                // Should complete quickly even with many calls
    98→                expect(endTime - startTime).toBeLessThan(50);
    99→            });
   100→        });
   101→    });
   102→});
